// 位置: src/auto-iteration.ts
// 预计: 1 天
```

**实现代码**:
```typescript
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private async notifyDashboard(event: string, data: any) {
    try {
      const { realtimeService } = getServices();
      await realtimeService.broadcast(event, data);
    } catch (error) {
      console.error('Failed to notify Dashboard:', error);
    }
  }

  async start() {
    // 迭代开始
    await this.notifyDashboard('iteration.started', {
      iterationNumber: this.iterationCount,
      timestamp: new Date()
    });

    // 产品经理分析
    await this.notifyDashboard('agent.started', {
      agent: 'product-manager',
      phase: 'analyzing'
    });

    const pmResult = await this.productManager.executeAndCollect(...);

    await this.notifyDashboard('agent.completed', {
      agent: 'product-manager',
      result: pmResult
    });

    // ... 其他 Agent 通知

    // 迭代完成
    await this.notifyDashboard('iteration.completed', {
      iterationNumber: this.iterationCount,
      duration: Date.now() - startTime,
      success: true
    });
  }
}
```

