// 在 AutoIterationEngine 类中添加 Dashboard 通信
export class AutoIterationEngine {
  private dashboardIntegration: any = null;

  constructor(config: Partial<IterationConfig> = {}) {
    // ... 原有代码

    // 如果启用 Dashboard,加载集成模块
    if (process.env.ENABLE_DASHBOARD === 'true') {
      this.initializeDashboardIntegration();
    }
  }

  private async initializeDashboardIntegration() {
    try {
      const { DashboardIntegration } = await import('./dashboard/integration/dashboard-integration');
      this.dashboardIntegration = new DashboardIntegration();
      await this.dashboardIntegration.start();
    } catch (error) {
      console.error('Failed to initialize dashboard integration:', error);
    }
  }

  // 在 runIteration() 方法中添加状态广播
  async runIteration(): Promise<void> {
    // 广播迭代开始
    await this.dashboardIntegration?.broadcastIterationStart({
      iterationNumber: this.iterationCount,
      timestamp: new Date()
    });

    // 原有的 Agent 执行逻辑...

    // 每个 Agent 执行完成后广播状态
    await this.dashboardIntegration?.broadcastAgentComplete({
      agentName: 'architect',
      status: 'completed',
      timestamp: new Date()
    });
  }
}
```

