#### 2.1 创建 `src/dashboard/integration/iteration-event-emitter.ts`
```typescript
/**
 * 迭代事件发射器 - 连接 AutoIterationEngine 和 Dashboard
 */
import { EventEmitter } from 'events';

export class IterationEventEmitter extends EventEmitter {
  private static instance: IterationEventEmitter;

  static getInstance(): IterationEventEmitter {
    if (!this.instance) {
      this.instance = new IterationEventEmitter();
    }
    return this.instance;
  }

  // 迭代生命周期事件
  emitIterationStart(data: { iterationNumber: number; timestamp: Date }) {
    this.emit('iteration.start', data);
  }

  emitIterationComplete(data: { iterationNumber: number; status: string }) {
    this.emit('iteration.complete', data);
  }

  // Agent 事件
  emitAgentStart(data: { agentName: string; task: string }) {
    this.emit('agent.start', data);
  }

  emitAgentProgress(data: { agentName: string; progress: number }) {
    this.emit('agent.progress', data);
  }

  emitAgentComplete(data: { agentName: string; result: string }) {
    this.emit('agent.complete', data);
  }
}
```

#### 2.2 修改 `src/dashboard/services/realtime.service.ts`
添加监听 IterationEventEmitter 并广播到 WebSocket:
```typescript
import { IterationEventEmitter } from '../integration/iteration-event-emitter';

export class RealtimeService {
  constructor(logger: any) {
    const emitter = IterationEventEmitter.getInstance();

    // 监听迭代事件并广播
    emitter.on('iteration.start', (data) => {
      this.broadcast('iteration.started', data);
    });

    emitter.on('agent.progress', (data) => {
      this.broadcast('agent.progress', data);
    });
  }
}
```

#### 2.3 在 AutoIterationEngine 中集成
```typescript
// 在 runIteration() 方法中添加
import { IterationEventEmitter } from '../dashboard/integration/iteration-event-emitter';

async runIteration(): Promise<void> {
  const emitter = IterationEventEmitter.getInstance();

  // 发送迭代开始事件
  emitter.emitIterationStart({
    iterationNumber: this.iterationCount,
    timestamp: new Date()
  });

  // 产品经理 Agent
  emitter.emitAgentStart({ agentName: 'product-manager', task: '分析需求' });
  const pmResult = await this.productManager.executeAndCollect(...);
  emitter.emitAgentComplete({ agentName: 'product-manager', result: pmResult });

  // ... 其他 Agent 类似处理
}
```

